import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import api from '../api/axiosConfig';
import { useToast } from '../context/ToastContext';
import { Fingerprint, Eye, EyeOff, User, Mail, ShieldCheck } from 'lucide-react';

const RegisterPage = () => {
  const [formData, setFormData] = useState({ 
    username: '', 
    email: '', 
    password: '', 
    confirmPassword: '' 
  });
  const [showPass, setShowPass] = useState(false);
  const [isRegistering, setIsRegistering] = useState(false);
  
  const addToast = useToast();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (formData.password.length < 8) {
      return addToast('SECURITY_PROTOCOL: Key must be at least 8 characters.', 'error');
    }
    
    if (formData.password !== formData.confirmPassword) {
      return addToast('VALIDATION_FAILURE: Security keys do not match.', 'error');
    }

    setIsRegistering(true);
    try {
      // Endpoint synchronized with FastAPI auth router
      await api.post('/auth/register', { 
        email: formData.email, 
        password: formData.password 
      });
      
      addToast('IDENTITY_CREATED: Node initialization successful.', 'success');
      navigate('/login');
    } catch (err) {
      addToast(err.response?.data?.detail || 'NODE_COLLISION: Identifier already exists.', 'error');
    } finally {
      setIsRegistering(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-[#121212] font-mono p-4">
      <div className="w-full max-w-md p-8 bg-[#1a1a1a] border border-white/10 rounded-2xl shadow-2xl relative overflow-hidden">
        
        {/* Top Accent Bar */}
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-emerald-500/50 to-transparent" />

        <div className="flex flex-col items-center mb-8">
          <div className="w-14 h-14 bg-emerald-500/10 rounded-xl flex items-center justify-center mb-4 border border-emerald-500/20 text-emerald-500 shadow-[0_0_15px_rgba(16,185,129,0.1)]">
            <Fingerprint size={28} />
          </div>
          <h2 className="text-white text-xl font-bold tracking-[0.3em] uppercase">Initialize_Node</h2>
          <p className="text-[9px] text-white/20 mt-1 uppercase tracking-widest">Protocol: User_Registration_v3</p>
        </div>
        
        <form onSubmit={handleSubmit} className="space-y-4">
          {/* Username Node */}
          <div className="relative">
            <label className="text-[10px] text-emerald-500 font-bold uppercase mb-2 block">Analyst_Handle</label>
            <div className="relative">
              <User className="absolute left-3 top-1/2 -translate-y-1/2 text-white/20" size={14} />
              <input 
                type="text"
                placeholder="USER_ID" 
                className="w-full bg-black/40 border border-white/10 p-3 pl-10 rounded-lg text-white focus:border-emerald-500/50 focus:ring-1 focus:ring-emerald-500/20 outline-none transition-all text-sm placeholder:text-white/10"
                value={formData.username}
                onChange={(e) => setFormData({ ...formData, username: e.target.value })} 
                required 
              />
            </div>
          </div>

          {/* Email Node */}
          <div className="relative">
            <label className="text-[10px] text-emerald-500 font-bold uppercase mb-2 block">Identity_Endpoint</label>
            <div className="relative">
              <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-white/20" size={14} />
              <input 
                type="email" 
                placeholder="EMAIL_ADDR" 
                className="w-full bg-black/40 border border-white/10 p-3 pl-10 rounded-lg text-white focus:border-emerald-500/50 focus:ring-1 focus:ring-emerald-500/20 outline-none transition-all text-sm placeholder:text-white/10"
                value={formData.email}
                onChange={(e) => setFormData({ ...formData, email: e.target.value })} 
                required 
              />
            </div>
          </div>
          
          {/* Password Node */}
          <div className="relative">
            <label className="text-[10px] text-emerald-500 font-bold uppercase mb-2 block">Security_Key</label>
            <div className="relative">
              <ShieldCheck className="absolute left-3 top-1/2 -translate-y-1/2 text-white/20" size={14} />
              <input 
                type={showPass ? "text" : "password"} 
                placeholder="MIN_8_CHARS" 
                className="w-full bg-black/40 border border-white/10 p-3 pl-10 pr-10 rounded-lg text-white focus:border-emerald-500/50 focus:ring-1 focus:ring-emerald-500/20 outline-none transition-all text-sm placeholder:text-white/10"
                value={formData.password}
                onChange={(e) => setFormData({ ...formData, password: e.target.value })} 
                required 
              />
              <button 
                type="button"
                onClick={() => setShowPass(!showPass)} 
                className="absolute right-3 top-1/2 -translate-y-1/2 text-white/20 hover:text-emerald-500 transition-colors"
              >
                {showPass ? <EyeOff size={16} /> : <Eye size={16} />}
              </button>
            </div>
          </div>
          
          {/* Verify Password Node */}
          <div className="relative">
            <label className="text-[10px] text-emerald-500 font-bold uppercase mb-2 block">Verify_Key</label>
            <input 
              type={showPass ? "text" : "password"} 
              placeholder="RE_ENTER_KEY" 
              className="w-full bg-black/40 border border-white/10 p-3 rounded-lg text-white focus:border-emerald-500/50 focus:ring-1 focus:ring-emerald-500/20 outline-none transition-all text-sm placeholder:text-white/10"
              value={formData.confirmPassword}
              onChange={(e) => setFormData({ ...formData, confirmPassword: e.target.value })} 
              required 
            />
          </div>
          
          <button 
            type="submit" 
            disabled={isRegistering}
            className={`w-full py-4 rounded-lg font-bold uppercase text-[11px] tracking-widest transition-all mt-4
              ${isRegistering 
                ? 'bg-emerald-500/10 text-emerald-500 cursor-not-allowed border border-emerald-500/20' 
                : 'bg-emerald-500 text-black hover:bg-emerald-400 active:scale-[0.98]'
              }`}
          >
            {isRegistering ? 'INITIALIZING_NODE...' : 'Create_Analyst_Account'}
          </button>
        </form>

        <div className="mt-8 pt-6 border-t border-white/5 text-center">
          <p className="text-[10px] text-white/20 uppercase tracking-widest">
            Already registered? <Link to="/login" className="text-emerald-500/70 hover:text-emerald-500 transition-colors font-bold">Access Terminal</Link>
          </p>
        </div>
      </div>
    </div>
  );
};

export default RegisterPage;
